import{_ as s,c as n,o as e,ag as p}from"./chunks/framework.bCALENAD.js";const u=JSON.parse('{"title":"数据库","description":"","frontmatter":{},"headers":[],"relativePath":"notes/nodejs/database.md","filePath":"notes/nodejs/database.md","lastUpdated":1774011314000}'),l={name:"notes/nodejs/database.md"};function t(o,a,i,r,c,d){return e(),n("div",null,[...a[0]||(a[0]=[p(`<h1 id="数据库" tabindex="-1">数据库 <a class="header-anchor" href="#数据库" aria-label="Permalink to &quot;数据库&quot;">​</a></h1><h2 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to &quot;基本概念&quot;">​</a></h2><p><strong>数据库（database）</strong> 是用来组织、存储和管理数据的仓库。用户可以对数据库中的数据进行新增、查询、更新、删除等操作。</p><div class="info custom-block"><p class="custom-block-title">常见的数据库及分类</p><p>市面上的数据库有很多种，最常见的数据库有如下几个：</p><ul><li>MySQL 数据库（目前使用最广泛、流行度最高的开源免费数据库；Community + Enterprise）</li><li>Oracle 数据库（收费）</li><li>SQL Server 数据库（收费）</li><li>MongoDB 数据库（Community + Enterprise）</li></ul><p>其中，MySQL、Oracle、SQL Server 属于传统型数据库（又叫做：关系型数据库 或 SQL 数据库），这三者的设计理念相同，用法比较类似。<br> 而 MongoDB 属于新型数据库（又叫做：非关系型数据库 或 NoSQL 数据库），它在一定程度上弥补了传统型数据库的缺陷。</p></div><blockquote><p>在传统型数据库中，数据的组织结构分为数据库(database)、数据表(table)、数据行(row)、字段(field)这 4 大部分组成。类似于Excel的工作簿、工作表、每一行数据、列。</p></blockquote><h2 id="安装并配置-mysql" tabindex="-1">安装并配置 MySQL <a class="header-anchor" href="#安装并配置-mysql" aria-label="Permalink to &quot;安装并配置 MySQL&quot;">​</a></h2><p>对于开发人员来说，只需要安装 <strong>MySQL Server</strong> 和 <strong>MySQL Workbench</strong> 这两个软件，就能满足开发的需要了。</p><ul><li><strong>MySQL Server</strong>: 专门用来提供数据存储和服务的软件。</li><li><strong>MySQL Workbench</strong>: 可视化的 MySQL 管理工具，通过它，可以方便的操作存储在 MySQL Server 中的数据。</li></ul><h2 id="使用sql管理数据库" tabindex="-1">使用SQL管理数据库 <a class="header-anchor" href="#使用sql管理数据库" aria-label="Permalink to &quot;使用SQL管理数据库&quot;">​</a></h2><h3 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h3><p><strong>1. 什么是 SQL</strong></p><p>SQL（Structured Query Language）是结构化查询语言，专门用来访问和处理数据库的编程语言。</p><p>三个关键点：</p><ol><li>SQL 是一门数据库编程语言</li><li>使用 SQL 语言编写出来的代码，叫做 SQL 语句</li><li>SQL 语言只能在关系型数据库中使用（例如 MySQL、Oracle、SQL Server）。非关系型数据库（例如 MongoDB）不支持 SQL 语言</li></ol><hr><p><strong>2. SQL 的学习目标</strong></p><blockquote><p>重点掌握如何使用 SQL 从数据表中：</p><p>查询数据（select）、插入数据（insert into）、更新数据（update）、删除数据（delete）</p></blockquote><blockquote><p>额外需要掌握的 4 种 SQL 语法：</p><p>where 条件、and 和 or 运算符、order by 排序、count(*) 函数</p></blockquote><h3 id="增删改查" tabindex="-1">增删改查 <a class="header-anchor" href="#增删改查" aria-label="Permalink to &quot;增删改查&quot;">​</a></h3><p><strong>1. 增</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>INSERT INTO 语句用于向数据表中插入新的数据行，语法格式如下：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1 -- 语法解读: 向指定的表中, 插入如下几列数据, 列的值通过 values ——指定</span></span>
<span class="line"><span>2 -- 注意: 列和值要一一对应, 多个列和多个值之间, 使用英文的逗号分隔</span></span>
<span class="line"><span>3 INSERT INTO table_name (列1, 列2,...) VALUES (值1, 值2,...)</span></span></code></pre></div><hr><p><strong>2. 删</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DELETE 语句用于删除表中的行。语法格式如下：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1 -- 语法解读:</span></span>
<span class="line"><span>2 -- 从指定的表中, 根据 WHERE 条件, 删除对应的数据行</span></span>
<span class="line"><span>3 DELETE FROM 表名称 WHERE 列名称 = 值</span></span></code></pre></div><hr><p><strong>3. 改</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Update 语句用于修改表中的数据。语法格式如下：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1 -- 语法解读:</span></span>
<span class="line"><span>2 -- 1. 用 UPDATE 指定要更新哪个表中的数据</span></span>
<span class="line"><span>3 -- 2. 用 SET 指定列对应的新值</span></span>
<span class="line"><span>4 -- 3. 用 WHERE 指定更新的条件</span></span>
<span class="line"><span>5 UPDATE 表名称 SET 列名称 = 新值 WHERE 列名称 = 某值</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7 -- 更新多列示例：</span></span>
<span class="line"><span>8 update users set password=&#39;admin123&#39;, status=1 where id=2</span></span></code></pre></div><hr><p><strong>4. 查</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SELECT 语句用于从表中查询数据。执行的结果被存储在一个结果表中（称为结果集）。语法格式如下：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1 -- 这是注释</span></span>
<span class="line"><span>2 -- 从 FROM 指定的【表中】，查询出【所有的】数据。 * 表示【所有列】</span></span>
<span class="line"><span>3 SELECT * FROM 表名称</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5 -- 从 FROM 指定的【表中】，查询出指定 列名称（字段）的数据。</span></span>
<span class="line"><span>6 SELECT 列名称 FROM 表名称</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">⚠️ 注意</p><p>SQL 语句中的关键字对大小写不敏感。SELECT 等效于 select，FROM 等效于 from。<br> 多个列使用英文逗号进行分隔</p></div><h3 id="where、and和or" tabindex="-1">where、and和or <a class="header-anchor" href="#where、and和or" aria-label="Permalink to &quot;where、and和or&quot;">​</a></h3><h3 id="排序order-by" tabindex="-1">排序order by <a class="header-anchor" href="#排序order-by" aria-label="Permalink to &quot;排序order by&quot;">​</a></h3><h3 id="count函数和as关键字" tabindex="-1">count函数和as关键字 <a class="header-anchor" href="#count函数和as关键字" aria-label="Permalink to &quot;count函数和as关键字&quot;">​</a></h3><h2 id="nodejs中使用mysql" tabindex="-1">nodejs中使用MySQL <a class="header-anchor" href="#nodejs中使用mysql" aria-label="Permalink to &quot;nodejs中使用MySQL&quot;">​</a></h2><h3 id="引入mysql模块" tabindex="-1">引入MySQL模块 <a class="header-anchor" href="#引入mysql模块" aria-label="Permalink to &quot;引入MySQL模块&quot;">​</a></h3><h3 id="增删改查-1" tabindex="-1">增删改查 <a class="header-anchor" href="#增删改查-1" aria-label="Permalink to &quot;增删改查&quot;">​</a></h3>`,37)])])}const b=s(l,[["render",t]]);export{u as __pageData,b as default};
